import{_ as a,o as t,c as s,j as r,a as b,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"人造天使α型","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/6.一次性改造/人造天使α型.md","filePath":"4.资源分区/2.改造与功法/改造/6.一次性改造/人造天使α型.md"}'),n={name:"4.资源分区/2.改造与功法/改造/6.一次性改造/人造天使α型.md"};function i(p,e,d,_,l,h){return t(),s("div",null,[...e[0]||(e[0]=[r("h1",{id:"人造天使α型",tabindex:"-1"},[b("人造天使α型 "),r("a",{class:"header-anchor",href:"#人造天使α型","aria-label":'Permalink to "人造天使α型"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风023元旦版")])])],-1),o('<h1 id="人造天使α型-1" tabindex="-1">人造天使α型 <a class="header-anchor" href="#人造天使α型-1" aria-label="Permalink to &quot;人造天使α型&quot;">​</a></h1><p>人造天使α型<br> 价格：B+3400<br> 描述：出自《天降之物》，拥有着强大的自我修复能力和无比恐怖的超远程火力，特化远程战斗能力的战略用万能天使，其可以购买的武装皆为远程攻击装置，包括永久追尾空对空导弹(Artemis) ， 超高热体压缩对舰炮I (HephaistosI)。<br> 其核心要害和正常人类一致(心脏对应动力炉，大脑对应芯片)，本兑换不附赠天王星系统以及最终兵器阿波罗，且兑换初始强度远逊于原著伊卡洛斯初始状态，请轮回者自行优化。<br> 效果：<br> 购买【人造天使α型】改造后，你的生物类型将转变为【构造体】，生命值将以1.5倍转为构造值；你获得【可变式羽翼系统】，与等同自身【传奇耐力】*1点快速维修，每点快速维修具有12点维修点数，可以正常治疗构造值。<br> ——<br> 【可变式羽翼系统】：你具有完美机动性的飞行能力，飞行速度等同自身基础移动速度。你可以以自由动作展开或收起羽翼，只有展开羽翼的情况下才能使用下属武装。</p><p>【专属武装/能力】<br> 永久追尾空对空导弹（Artemis）<br> 价格：B+2000<br> 分类：导弹<br> 武器伤害：20L<br> 武器特性：【高速5】【破甲3】【湮灭】<br> 装弹量：见下<br> 武器射程：200米<br> 描述：与制导跟踪导弹类似，主神提供的版本在追踪性能上更加优秀，但射程和效果上有所降低，展开发射功能会同时占用双手。<br> 效果：<br> 该武装使用正常射击检定，专业改为导弹专业，同时对落点40+【传奇智力*20】米范围内的所有目标（不分敌我）造成伤害；该武器无需填装弹药，如同具有【无限子弹】一样进行处理。</p><p>绝对防御圈（Aegis）<br> 价格：B+2000<br> 描述：可以防御除阿斯特蕾亚的超振动粒子光剑以外的已知一切攻击。主神提供的是较低性能的常驻版本。<br> 效果：<br> 购买该能力后，你的盔甲位将永久被占据，如同穿戴了一件防御能力为20/20的轻甲进行处理，防御类型为力场防御，具有【防弹】【防能量武器】特性。<br> ——<br> 你可以使用反射动作展开绝对防御圈（Aegis），为等同15+传奇智力*10米范围内所有的友方单位提供同样的效果，此时绝对防御圈具有【适应】特性，基于其提供的防御生效，适应也对你自己产生效果。享受这一效果这需要友方目标没有穿戴盔甲，若穿戴盔甲则可以选择放弃原有盔甲提供的防御和效果，从而获得这一能力提供的作用。</p><p>超高热体压缩对舰炮Ⅰ（HephaistosⅠ）<br> 价格：A+4000<br> 动作：整轮动作<br> 范围：敏感范围<br> 目标：敌对目标<br> 消耗：-<br> 持续：见下<br> 描述：超高热体压缩对舰炮Ⅰ（HephaistosⅠ），原本是天王星系统内的武器，一击可毁灭一支舰队，但漫画版提供的则是平时形态也能使用的装备。<br> 效果：<br> 你需要使用整轮动作展开【超高热体压缩对舰炮Ⅰ（HephaistosⅠ）】，随后在下一轮开始时，正常进行一次普通枪械射击攻击，本次攻击无法附带招式，将对敏感范围内的所有敌对目标造成伤害，攻击具有【幻灭】【能量武器】【超级贯穿】【8加骰】特性。<br> 这一攻击附带【熔毁X】，熔毁数值等同自身传奇智力*4+10点，持续存在的时间为一场景（同一来源的熔毁只会生效一次）。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=a(n,[["render",i]]);export{f as __pageData,m as default};
